mapper.select:
/* 알람 목록 조회 */
select 
	alarm_idx, site_id, device_id, device_type, std_date, alarm_type, alarm_msg, 
	alarm_cfm_yn, alarm_cfm_date, alarm_cfm_uid, alarm_note, reg_date, mod_date
from tb_alarm
where 1=1
and site_id = #{siteId }

and alarm_cfm_yn = #{alarmCfmYn }


and std_date between str_to_date(#{schTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{schTermTo },'%Y%m%d%H%i%s')

order std_date

/* 알람 타입건수 조회 */
select 
	count(if(alarm_type=1, alarm_type, null)) as alert_cnt, 
	count(if(alarm_type=2, alarm_type, null)) as warning_cnt
from tb_alarm
where 1=1
and site_id = #{siteId }

and alarm_cfm_yn = #{alarmCfmYn }


and std_date between str_to_date(#{schTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{schTermTo },'%Y%m%d%H%i%s')

order std_date
